/* ==========================================================================
   Ambient Sound Toggle (M005/S03)
   - Floating fixed circle, bottom-right
   - aria-pressed="false"  → muted (🔇, default state)
   - aria-pressed="true"   → playing (🔊, accent tint)
   ========================================================================== */

.sound-toggle {
  /* Position — fixed bottom-right, above all content */
  position: fixed;
  bottom: 1.25rem;
  right: 1.25rem;
  z-index: 200;

  /* Size — 48px satisfies ≥44px touch-target requirement */
  width: 3rem;   /* 48px */
  height: 3rem;
  padding: 0;

  /* Shape */
  border-radius: 50%;

  /* Surface — card palette for cohesion with existing UI */
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  box-shadow: var(--shadow-elevated);

  /* Typography */
  font-size: 1.25rem;
  line-height: 1;
  cursor: pointer;

  /* Reset button defaults */
  appearance: none;
  -webkit-appearance: none;

  /* Transitions */
  transition:
    background var(--duration-fast) var(--ease-out),
    border-color var(--duration-fast) var(--ease-out),
    box-shadow var(--duration-fast) var(--ease-out),
    transform var(--duration-fast) var(--ease-out);

  /* Center the emoji icon */
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Hover / focus states */
.sound-toggle:hover {
  background: var(--color-sepia-light);
  border-color: var(--color-sepia-mid);
  box-shadow: var(--shadow-elevated), 0 0 0 3px rgba(59, 47, 32, 0.06);
  transform: scale(1.05);
}

.sound-toggle:focus-visible {
  outline: 2px solid var(--color-celeste);
  outline-offset: 3px;
}

/* Active / playing state — accent tint signals sound is on */
.sound-toggle[aria-pressed="true"] {
  background: color-mix(in srgb, var(--color-celeste) 12%, var(--color-card-bg));
  border-color: var(--color-celeste-soft);
  box-shadow: var(--shadow-elevated), 0 0 0 2px var(--color-celeste-soft);
}

.sound-toggle[aria-pressed="true"]:hover {
